namespace sv_5ff496e42517483ead32a83b7618a0f2.Models;

/// <summary>
/// Mutable form state shared across all steps of the job application wizard.
/// </summary>
public class JobApplicationFormModel
{
    // Step 1 — Personal Info
    public string FullName { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
    public string Address { get; set; } = string.Empty;

    // Step 2 — Work History
    public List<WorkEntryModel> WorkEntries { get; set; } = [new()];

    // Step 3 — References
    public List<ReferenceModel> References { get; set; } = [new(), new()];

    // Step 4 — Cover Letter
    public string CoverLetter { get; set; } = string.Empty;

    public JobApplication ToRecord() => new(
        new PersonalInfo(FullName, Email, Phone, Address),
        new WorkHistory(WorkEntries.Select(w => new WorkEntry(
            w.Company, w.Title, w.StartDate, w.IsCurrent ? null : w.EndDate, w.Description)).ToList()),
        References.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
        CoverLetter
    );
}

public class WorkEntryModel
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public DateTime StartDate { get; set; } = DateTime.Today;
    public DateTime? EndDate { get; set; } = DateTime.Today;
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = string.Empty;
}

public class ReferenceModel
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

@namespace sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var status = step < CurrentStep ? "completed"
                   : step == CurrentStep ? "current"
                   : "future";

        <button class="step @status"
                disabled="@(status == "future")"
                @onclick="() => OnStepClicked(step)"
                aria-current="@(status == "current" ? "step" : null)">
            <span class="step-number">
                @if (status == "completed")
                {
                    <span class="checkmark">✓</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>

        @if (step < StepNames.Length - 1)
        {
            <span class="step-connector @(step < CurrentStep ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnNavigate { get; set; }

    private async Task OnStepClicked(int step)
    {
        if (step < CurrentStep)
            await OnNavigate.InvokeAsync(step);
    }
}

@using sv_5ff496e42517483ead32a83b7618a0f2.Models
@namespace sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply

<section class="form-step">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label for="fullName">Full Name <span class="required">*</span></label>
        <input id="fullName" type="text" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
    </div>

    <div class="form-group">
        <label for="email">Email <span class="required">*</span></label>
        <input id="email" type="email" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
    </div>

    <div class="form-group">
        <label for="phone">Phone <span class="required">*</span></label>
        <input id="phone" type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
    </div>

    <div class="form-group">
        <label for="address">Address <span class="required">*</span></label>
        <textarea id="address" rows="2" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State ZIP"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @if (IsValidating)
            {
                <span>Validating…</span>
            }
            else
            {
                <span>Next</span>
            }
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public JobApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
        { ErrorMessage = "Full name is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Email))
        { ErrorMessage = "Email is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        { ErrorMessage = "Phone number is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Address))
        { ErrorMessage = "Address is required."; return; }

        IsValidating = true;
        try
        {
            var valid = await ValidateEmail(Model.Email);
            if (!valid)
            { ErrorMessage = "Please enter a valid email address."; return; }
        }
        finally { IsValidating = false; }

        await OnNext.InvokeAsync();
    }
}

@using sv_5ff496e42517483ead32a83b7618a0f2.Models
@namespace sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply

<section class="form-step">
    <h2>Work History</h2>

    @for (int i = 0; i < Model.WorkEntries.Count; i++)
    {
        var index = i;
        var entry = Model.WorkEntries[index];

        <fieldset class="work-entry">
            <legend>Position @(index + 1)</legend>

            @if (Model.WorkEntries.Count > 1)
            {
                <button type="button" class="btn btn-danger btn-sm remove-btn" @onclick="() => RemoveEntry(index)">Remove</button>
            }

            <div class="form-group">
                <label>Company Name <span class="required">*</span></label>
                <input type="text" @bind="entry.Company" @bind:event="oninput" placeholder="Acme Corp" />
            </div>

