{"file_text": "@namespace sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var status = step < CurrentStep ? "completed"
                   : step == CurrentStep ? "current"
                   : "future";

        <button class="step @status"
                disabled="@(status == "future")"
                @onclick="() => OnStepClicked(step)"
                aria-current="@(status == "current" ? "step" : null)">
            <span class="step-number">
                @if (status == "completed")
                {
                    <span class="checkmark">✓</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>

        @if (step < StepNames.Length - 1)
        {
            <span class="step-connector @(step < CurrentStep ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnNavigate { get; set; }

    private async Task OnStepClicked(int step)
    {
        if (step < CurrentStep)
            await OnNavigate.InvokeAsync(step);
    }
}
