    </div>

    <div class="form-group">
        <label for="phone">Phone <span class="required">*</span></label>
        <input id="phone" type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
    </div>

    <div class="form-group">
        <label for="address">Address <span class="required">*</span></label>
        <textarea id="address" rows="2" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State ZIP"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @if (IsValidating)
            {
                <span>Validating…</span>
            }
            else
            {
                <span>Next</span>
            }
        </button>
    </div>
