@code {
    [Parameter, EditorRequired]
    public JobApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
        { ErrorMessage = "Full name is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Email))
        { ErrorMessage = "Email is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        { ErrorMessage = "Phone number is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Address))
        { ErrorMessage = "Address is required."; return; }

        IsValidating = true;
        try
        {
            var valid = await ValidateEmail(Model.Email);
            if (!valid)
            { ErrorMessage = "Please enter a valid email address."; return; }
        }
        finally { IsValidating = false; }

        await OnNext.InvokeAsync();
    }
}
