    @for (int i = 0; i < Model.WorkEntries.Count; i++)
    {
        var index = i;
        var entry = Model.WorkEntries[index];

        <fieldset class="work-entry">
            <legend>Position @(index + 1)</legend>

            @if (Model.WorkEntries.Count > 1)
            {
                <button type="button" class="btn btn-danger btn-sm remove-btn" @onclick="() => RemoveEntry(index)">Remove</button>
            }

            <div class="form-group">
                <label>Company Name <span class="required">*</span></label>
                <input type="text" @bind="entry.Company" @bind:event="oninput" placeholder="Acme Corp" />
            </div>

            <div class="form-group">
                <label>Job Title <span class="required">*</span></label>
                <input type="text" @bind="entry.Title" @bind:event="oninput" placeholder="Software Engineer" />
            </div>

            <div class="form-row">
                <div class="form-group">
                    <label>Start Date <span class="required">*</span></label>
                    <input type="date" @bind="entry.StartDate" />
                </div>

                <div class="form-group">
                    <label>End Date</label>
                    <input type="date" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                    <label class="checkbox-label">
                        <input type="checkbox" @bind="entry.IsCurrent" /> Currently working here
                    </label>
                </div>
            </div>

            <div class="form-group">
                <label>Description</label>
                <textarea rows="3" @bind="entry.Description" @bind:event="oninput" placeholder="Describe your role and accomplishments…"></textarea>
            </div>
        </fieldset>
    }

    <button type="button" class="btn btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public JobApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry() => Model.WorkEntries.Add(new WorkEntryModel());

    private void RemoveEntry(int index) => Model.WorkEntries.RemoveAt(index);

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var entry in Model.WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}
