@using sv_5ff496e42517483ead32a83b7618a0f2.Models
@namespace sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply

<section class="form-step">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label for="fullName">Full Name <span class="required">*</span></label>
        <input id="fullName" type="text" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
    </div>

    <div class="form-group">
        <label for="email">Email <span class="required">*</span></label>
        <input id="email" type="email" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
    </div>

    <div class="form-group">
        <label for="phone">Phone <span class="required">*</span></label>
        <input id="phone" type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
    </div>

    <div class="form-group">
        <label for="address">Address <span class="required">*</span></label>
        <textarea id="address" rows="2" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State ZIP"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @if (IsValidating)
            {
                <span>Validating…</span>
            }
            else
            {
                <span>Next</span>
            }
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public JobApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
        { ErrorMessage = "Full name is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Email))
        { ErrorMessage = "Email is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        { ErrorMessage = "Phone number is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Address))
        { ErrorMessage = "Address is required."; return; }

        IsValidating = true;
        try
        {
            var valid = await ValidateEmail(Model.Email);
            if (!valid)
            { ErrorMessage = "Please enter a valid email address."; return; }
        }
        finally { IsValidating = false; }

        await OnNext.InvokeAsync();
    }
}

