@using sv_5ff496e42517483ead32a83b7618a0f2.Models
@namespace sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply

<section class="form-step">
    <h2>Work History</h2>

    @for (int i = 0; i < Model.WorkEntries.Count; i++)
    {
        var index = i;
        var entry = Model.WorkEntries[index];

        <fieldset class="work-entry">
            <legend>Position @(index + 1)</legend>

            @if (Model.WorkEntries.Count > 1)
            {
                <button type="button" class="btn btn-danger btn-sm remove-btn" @onclick="() => RemoveEntry(index)">Remove</button>
            }

            <div class="form-group">
                <label>Company Name <span class="required">*</span></label>
                <input type="text" @bind="entry.Company" @bind:event="oninput" placeholder="Acme Corp" />
            </div>

            <div class="form-group">
                <label>Job Title <span class="required">*</span></label>
                <input type="text" @bind="entry.Title" @bind:event="oninput" placeholder="Software Engineer" />
            </div>

            <div class="form-row">
                <div class="form-group">
                    <label>Start Date <span class="required">*</span></label>
                    <input type="date" @bind="entry.StartDate" />
                </div>

                <div class="form-group">
                    <label>End Date</label>
                    <input type="date" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                    <label class="checkbox-label">
                        <input type="checkbox" @bind="entry.IsCurrent" /> Currently working here
                    </label>
                </div>
            </div>

            <div class="form-group">
                <label>Description</label>
                <textarea rows="3" @bind="entry.Description" @bind:event="oninput" placeholder="Describe your role and accomplishments…"></textarea>
            </div>
        </fieldset>
    }

    <button type="button" class="btn btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public JobApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry() => Model.WorkEntries.Add(new WorkEntryModel());

    private void RemoveEntry(int index) => Model.WorkEntries.RemoveAt(index);

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var entry in Model.WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@using sv_5ff496e42517483ead32a83b7618a0f2.Models
@namespace sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply

<section class="form-step">
    <h2>References</h2>

    @for (int i = 0; i < Model.References.Count; i++)
    {
        var index = i;
        var reference = Model.References[index];

        <fieldset class="reference-entry">
            <legend>Reference @(index + 1)</legend>

            @if (Model.References.Count > 2)
            {
                <button type="button" class="btn btn-danger btn-sm remove-btn" @onclick="() => RemoveReference(index)">Remove</button>
            }

            <div class="form-group">
                <label>Name <span class="required">*</span></label>
                <input type="text" @bind="reference.Name" @bind:event="oninput" placeholder="Jane Smith" />
            </div>

            <div class="form-group">
                <label>Relationship <span class="required">*</span></label>
                <input type="text" @bind="reference.Relationship" @bind:event="oninput" placeholder="Former Manager" />
            </div>

            <div class="form-row">
                <div class="form-group">
                    <label>Email <span class="required">*</span></label>
                    <input type="email" @bind="reference.Email" @bind:event="oninput" placeholder="jane@example.com" />
                </div>

                <div class="form-group">
                    <label>Phone <span class="required">*</span></label>
                    <input type="tel" @bind="reference.Phone" @bind:event="oninput" placeholder="(555) 987-6543" />
                </div>
            </div>
        </fieldset>
    }

    @if (Model.References.Count < 3)
    {
        <button type="button" class="btn btn-secondary" @onclick="AddReference">+ Add Reference</button>
    }

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public JobApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (Model.References.Count < 3)
            Model.References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index) => Model.References.RemoveAt(index);

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var r in Model.References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@using sv_5ff496e42517483ead32a83b7618a0f2.Models
@namespace sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply

<section class="form-step">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label for="coverLetter">Write your cover letter below</label>
        <textarea id="coverLetter"
                  rows="12"
                  maxlength="@MaxLength"
                  @bind="Model.CoverLetter"
                  @bind:event="oninput"
                  placeholder="Dear Hiring Manager…"></textarea>
        <div class="char-count @(Model.CoverLetter.Length > MaxLength ? "over-limit" : "")">
            @Model.CoverLetter.Length / @MaxLength characters
        </div>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="form-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired]
    public JobApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private async Task HandleNext()
    {
        ErrorMessage = null;
        if (string.IsNullOrWhiteSpace(Model.CoverLetter))
        { ErrorMessage = "A cover letter is required."; return; }
        if (Model.CoverLetter.Length > MaxLength)
        { ErrorMessage = $"Cover letter must be {MaxLength} characters or fewer."; return; }
        await OnNext.InvokeAsync();
    }
}

@using sv_5ff496e42517483ead32a83b7618a0f2.Models
@namespace sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply

<section class="form-step review-step">
    <h2>Review & Submit</h2>

    @if (IsSubmitted)
    {
        <div class="confirmation">
            <div class="confirmation-icon">✓</div>
            <h3>Application Submitted!</h3>
            <p>Your application has been received. Your application ID is:</p>
            <p class="application-id">#@ApplicationId</p>
        </div>
    }
    else
    {
        <div class="review-section">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
            </div>
            <dl class="review-data">
                <dt>Name</dt><dd>@Model.FullName</dd>
                <dt>Email</dt><dd>@Model.Email</dd>
                <dt>Phone</dt><dd>@Model.Phone</dd>
                <dt>Address</dt><dd>@Model.Address</dd>
            </dl>
        </div>

        <div class="review-section">
            <div class="review-header">
                <h3>Work History</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in Model.WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong>
                    <br />
                    <span class="review-dates">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="review-description">@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h3>References</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in Model.References)
            {
                <div class="review-entry">
                    <strong>@r.Name</strong> — @r.Relationship
                    <br />
                    <span>@r.Email · @r.Phone</span>
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h3>Cover Letter</h3>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
            </div>
            <p class="review-cover-letter">@Model.CoverLetter</p>
        </div>

        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="error-message" role="alert">@ErrorMessage</div>
        }

        <div class="form-actions">
            <button class="btn btn-outline" @onclick="OnBack">Back</button>
            <button class="btn btn-primary btn-submit" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span>Submitting…</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
</section>

@code {
    [Parameter, EditorRequired]
    public JobApplicationFormModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnEdit { get; set; }

    [Parameter, EditorRequired]
    public Func<Task<int>> SubmitApplication { get; set; } = default!;

    private bool IsSubmitting;
    private bool IsSubmitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;
        try
        {
            ApplicationId = await SubmitApplication();
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally { IsSubmitting = false; }
    }
}

