@page "/apply"
@rendermode InteractiveServer

@using sv_5ff496e42517483ead32a83b7618a0f2.Components.Pages.Apply
@using sv_5ff496e42517483ead32a83b7618a0f2.Models
@using sv_5ff496e42517483ead32a83b7618a0f2.Services

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="currentStep" OnNavigate="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="formModel"
                              OnNext="NextStep"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;
        case 1:
            <WorkHistoryStep Model="formModel"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep Model="formModel"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep Model="formModel"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Model="formModel"
                        OnBack="PreviousStep"
                        OnEdit="GoToStep"
                        SubmitApplication="Submit" />
            break;
    }
</div>

@code {
    private int currentStep;
    private readonly JobApplicationFormModel formModel = new();

    private void NextStep() => currentStep++;
    private void PreviousStep() => currentStep--;
    private void GoToStep(int step) => currentStep = step;

    private async Task<int> Submit()
    {
        var application = formModel.ToRecord();
        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

/* ── Layout ── */
.apply-container {
    max-width: 720px;
    margin: 2rem auto;
    padding: 0 1rem;
}

.apply-container h1 {
    text-align: center;
    margin-bottom: 1.5rem;
    color: #1a1a2e;
}

/* ── Step Indicator ── */
.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    margin-bottom: 2rem;
    flex-wrap: wrap;
}

.step-indicator .step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.35rem;
    background: none;
    border: none;
    cursor: default;
    padding: 0.25rem 0.5rem;
    min-width: 5.5rem;
}

.step-indicator .step.completed {
    cursor: pointer;
}

.step-indicator .step-number {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.85rem;
    border: 2px solid #ccc;
    color: #999;
    background: #fff;
    transition: all 0.2s;
}

.step.current .step-number {
    border-color: #4361ee;
    background: #4361ee;
    color: #fff;
}

.step.completed .step-number {
    border-color: #2ecc71;
    background: #2ecc71;
    color: #fff;
}

.step-label {
    font-size: 0.75rem;
    color: #999;
    text-align: center;
    white-space: nowrap;
}

.step.current .step-label {
    color: #4361ee;
    font-weight: 600;
}

.step.completed .step-label {
    color: #2ecc71;
}

.step-connector {
    flex: 0 0 2rem;
    height: 2px;
    background: #ddd;
    align-self: flex-start;
    margin-top: 1rem;
}

.step-connector.completed {
    background: #2ecc71;
}

/* ── Form Step ── */
.form-step {
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.5rem;
}

.form-step h2 {
    margin-top: 0;
    margin-bottom: 1.25rem;
    color: #1a1a2e;
    font-size: 1.35rem;
}

.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.3rem;
    font-weight: 500;
    font-size: 0.9rem;
    color: #333;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="tel"],
.form-group input[type="date"],
.form-group textarea {
    width: 100%;
    padding: 0.5rem 0.65rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
    font-family: inherit;
    box-sizing: border-box;
    transition: border-color 0.15s;
}

.form-group input:focus,
.form-group textarea:focus {
    outline: none;
    border-color: #4361ee;
    box-shadow: 0 0 0 2px rgba(67, 97, 238, 0.15);
}

.form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
}

.required {
    color: #e74c3c;
}

.checkbox-label {
    display: inline-flex !important;
    align-items: center;
    gap: 0.35rem;
    font-weight: 400 !important;
    margin-top: 0.35rem;
    font-size: 0.85rem !important;
    cursor: pointer;
}

.checkbox-label input[type="checkbox"] {
    width: auto;
}

/* ── Fieldsets ── */
fieldset.work-entry,
fieldset.reference-entry {
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 1rem;
    margin-bottom: 1rem;
    position: relative;
}

fieldset legend {
    font-weight: 600;
    font-size: 0.95rem;
    color: #555;
    padding: 0 0.35rem;
}

.remove-btn {
    position: absolute;
    top: 0.5rem;
    right: 0.5rem;
}

/* ── Buttons ── */
.form-actions {
    display: flex;
    justify-content: space-between;
    margin-top: 1.5rem;
    gap: 0.75rem;
}

.btn {
    padding: 0.55rem 1.25rem;
    border: none;
    border-radius: 4px;
    font-size: 0.95rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s, opacity 0.15s;
}

.btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-primary {
    background: #4361ee;
    color: #fff;
    margin-left: auto;
}

.btn-primary:hover:not(:disabled) {
    background: #3451d1;
}

.btn-outline {
    background: transparent;
    border: 1px solid #ccc;
    color: #555;
}

.btn-outline:hover:not(:disabled) {
    background: #f5f5f5;
}

.btn-secondary {
    background: #f0f0f0;
    color: #333;
}

.btn-secondary:hover:not(:disabled) {
    background: #e0e0e0;
}

.btn-danger {
    background: #e74c3c;
    color: #fff;
}

.btn-sm {
    padding: 0.25rem 0.6rem;
    font-size: 0.8rem;
}

.btn-link {
    background: none;
    border: none;
    color: #4361ee;
    cursor: pointer;
    font-size: 0.9rem;
    text-decoration: underline;
    padding: 0;
}

.btn-link:hover {
    color: #3451d1;
}

.btn-submit {
    padding: 0.65rem 2rem;
    font-size: 1rem;
}

/* ── Character Count ── */
.char-count {
    text-align: right;
    font-size: 0.8rem;
    color: #888;
    margin-top: 0.25rem;
}

.char-count.over-limit {
    color: #e74c3c;
    font-weight: 600;
}

/* ── Error ── */
.error-message {
    background: #fef2f2;
    border: 1px solid #fecaca;
    color: #b91c1c;
    padding: 0.6rem 0.85rem;
    border-radius: 4px;
    margin-top: 0.75rem;
    font-size: 0.9rem;
}

/* ── Review Step ── */
.review-section {
    border-bottom: 1px solid #eee;
    padding-bottom: 1rem;
    margin-bottom: 1rem;
}

.review-section:last-of-type {
    border-bottom: none;
}

.review-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.review-header h3 {
    margin: 0 0 0.5rem 0;
    font-size: 1.05rem;
    color: #333;
}

.review-data {
    display: grid;
    grid-template-columns: 7rem 1fr;
    gap: 0.25rem 1rem;
    margin: 0;
}

.review-data dt {
    font-weight: 500;
    color: #666;
    font-size: 0.9rem;
}

.review-data dd {
    margin: 0;
    font-size: 0.9rem;
}

.review-entry {
    margin-bottom: 0.75rem;
    font-size: 0.9rem;
}

.review-dates {
    color: #666;
    font-size: 0.85rem;
}

.review-description {
    color: #555;
    margin: 0.25rem 0 0;
    font-size: 0.85rem;
}

.review-cover-letter {
    white-space: pre-wrap;
    font-size: 0.9rem;
    color: #444;
    background: #f9f9f9;
    padding: 0.75rem;
    border-radius: 4px;
}

/* ── Confirmation ── */
.confirmation {
    text-align: center;
    padding: 2rem 0;
}

.confirmation-icon {
    width: 4rem;
    height: 4rem;
    border-radius: 50%;
    background: #2ecc71;
    color: #fff;
    font-size: 2rem;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 1rem;
}

.confirmation h3 {
    color: #2ecc71;
    font-size: 1.5rem;
    margin-bottom: 0.5rem;
}

.application-id {
    font-size: 1.5rem;
    font-weight: 700;
    color: #4361ee;
}

